mapper.select:
select u.id, u.dept_code as user_dept_code, u.login_name, u.name, u.code, u.email, u.phonenumber, u.status, u.entry_date, u.leave_date, u.is_deleted, u.login_ip, u.login_date, u.create_by, u.create_time, u.remarks, d.dept_code, d.dept_name, d.leader from sys_user u
left join sys_dept d on u.dept_code = d.dept_code
where u.is_deleted = '0'

	AND u.id = #{userId}


	AND u.login_name like concat('%', #{userName}, '%')


	AND u.status = #{status}


	AND u.phonenumber like concat('%', #{phonenumber}, '%')


	AND date_format(u.create_time,'%Y%m%d') >= date_format(#{params.beginTime},'%Y%m%d')


	AND date_format(u.create_time,'%Y%m%d') <= date_format(#{params.endTime},'%Y%m%d')


${params.dataScope}

select distinct u.id, u.login_name, u.code, u.email, u.phonenumber, u.status, u.entry_date, u.leave_date, u.create_time from sys_user u left join sys_dept d on u.dept_code = d.dept_code left join sys_user_role ur on u.id = ur.user_id left join sys_role r on r.id = ur.role_id where u.is_deleted = '0' and r.id = #{roleId}
AND u.login_name like concat('%', #{userName}, '%')
AND u.phonenumber like concat('%', #{phonenumber}, '%')
${params.dataScope}

mapper.update:
update sys_user
login_name = #{userName}, dept_code = #{deptCode}, code = #{nickName}, name = #{name}, email = #{email}, phonenumber = #{phonenumber}, password = #{password}, status = #{status}, entry_date = #{entryDate}, leave_date = #{leaveDate}, login_ip = #{loginIp}, login_date = #{loginDate}, update_by = #{updateBy}, remarks = #{remarks}, update_time = sysdate()
where id = #{userId}
